                        } else {
                            if (window.NativeBridge._cameraReject) {
                                window.NativeBridge._cameraReject('Camera cancelled or failed');
                            }
                        }
                        window.NativeBridge._cameraResolve = null;
                        window.NativeBridge._cameraReject = null;
                    },
                    
                    hasCameraPermission: function() {
