                    },
                    
                    removeItem: function(key) {
                        if (window.AndroidBridge) {
                            window.AndroidBridge.removeStorageItem(key);
                        }
                    },
                    
                    getAllItems: function() {
                        if (window.AndroidBridge) {
                            var json = window.AndroidBridge.getAllStorageItems();
                            return JSON.parse(json);
                        }
                        return {};
                    },
                    
                    clearStorage: function() {
                        if (window.AndroidBridge) {
                            window.AndroidBridge.clearStorage();
                        }
                    },
                    
                    // Push Notifications
                    requestNotificationPermission: function() {
                        return new Promise(function(resolve) {
                            window.NativeBridge._notificationPermResolve = resolve;
                            if (window.AndroidBridge) {
                                window.AndroidBridge.requestNotificationPermission();
                            }
                        });
                    },
                    
                    _onNotificationPermissionResult: function(granted) {
                        if (window.NativeBridge._notificationPermResolve) {
                            window.NativeBridge._notificationPermResolve(granted);
                            window.NativeBridge._notificationPermResolve = null;
                        }
                    },
                    
                    hasNotificationPermission: function() {
                        if (window.AndroidBridge) {
                            return window.AndroidBridge.hasNotificationPermission();
                        }
                        return false;
                    },
                    
                    showLocalNotification: function(title, message, id) {
                        if (window.AndroidBridge) {
                            window.AndroidBridge.showLocalNotification(title, message, id || 0);
                        }
                    },
                    
                    getFCMToken: function() {
                        return new Promise(function(resolve) {
                            window.NativeBridge._tokenResolve = resolve;
                            if (window.AndroidBridge) {
                                window.AndroidBridge.getFCMToken();
                            }
                        });
                    },
                    
                    _onFCMToken: function(token) {
                        if (window.NativeBridge._tokenResolve) {
                            window.NativeBridge._tokenResolve(token);
                            window.NativeBridge._tokenResolve = null;
                        }
                    },
                    
                    subscribeTopic: function(topic) {
                        if (window.AndroidBridge) {
                            window.AndroidBridge.subscribeToTopic(topic);
                        }
                    },
                    
                    unsubscribeTopic: function(topic) {
                        if (window.AndroidBridge) {
                            window.AndroidBridge.unsubscribeFromTopic(topic);
                        }
                    },
                    
                    // Utility
                    getDeviceInfo: function() {
                        if (window.AndroidBridge) {
                            var json = window.AndroidBridge.getDeviceInfo();
