                        this._listeners[event].push(callback);
                    },
                    off: function(event, callback) {
                        if (this._listeners[event]) {
                            this._listeners[event] = this._listeners[event].filter(function(cb) { return cb !== callback; });
                        }
                    },
                    _emit: function(event, data) {
