package com.example.hybridapp

import android.Manifest
import android.content.Context
import android.content.pm.PackageManager
import android.os.Build
import android.util.Log
import android.webkit.JavascriptInterface
import android.widget.Toast
import androidx.core.content.ContextCompat
import com.google.firebase.messaging.FirebaseMessaging
import org.json.JSONObject

class NativeBridge(private val activity: MainActivity) {

    companion object {
        private const val TAG = "NativeBridge"
        private const val PREFS_NAME = "HybridAppPrefs"
    }

    private val sharedPreferences = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    // ==================== Camera ====================

    @JavascriptInterface
    fun openCamera(callbackName: String) {
        Log.d(TAG, "openCamera called with callback: $callbackName")
        activity.runOnUiThread {
            activity.requestCameraAccess(callbackName)
        }
    }

    @JavascriptInterface
    fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            activity, Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }

    // ==================== Local Storage ====================

    @JavascriptInterface
    fun setStorageItem(key: String, value: String) {
        Log.d(TAG, "setStorageItem: $key = $value")
        sharedPreferences.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getStorageItem(key: String): String? {
        val value = sharedPreferences.getString(key, null)
        Log.d(TAG, "getStorageItem: $key = $value")
        return value
    }

    @JavascriptInterface
    fun removeStorageItem(key: String) {
        Log.d(TAG, "removeStorageItem: $key")
        sharedPreferences.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun getAllStorageItems(): String {
        val allEntries = sharedPreferences.all
        val json = JSONObject()
        for ((key, value) in allEntries) {
            json.put(key, value.toString())
        }
        return json.toString()
    }

    @JavascriptInterface
    fun clearStorage() {
        Log.d(TAG, "clearStorage")
        sharedPreferences.edit().clear().apply()
    }

    // ==================== Push Notifications ====================

    @JavascriptInterface
    fun requestNotificationPermission() {
        Log.d(TAG, "requestNotificationPermission")
        activity.runOnUiThread {
            activity.requestNotificationPermission()
        }
    }

    @JavascriptInterface
    fun hasNotificationPermission(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            ContextCompat.checkSelfPermission(
                activity, Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
        } else {
            true
        }
    }

    @JavascriptInterface
    fun showLocalNotification(title: String, message: String, notificationId: Int) {
        Log.d(TAG, "showLocalNotification: $title - $message")
        activity.runOnUiThread {
            activity.showNotification(title, message, notificationId)
        }
    }

    @JavascriptInterface
    fun getFCMToken() {
        Log.d(TAG, "getFCMToken")
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                val token = task.result
                Log.d(TAG, "FCM Token: $token")
                activity.runOnUiThread {
                    val webView = activity.findViewById<android.webkit.WebView>(R.id.webView)
                    webView.evaluateJavascript(
                        "javascript:window.NativeBridge._onFCMToken('$token')", null
                    )
                }
            } else {
                Log.e(TAG, "Failed to get FCM token", task.exception)
                activity.runOnUiThread {
                    val webView = activity.findViewById<android.webkit.WebView>(R.id.webView)
                    webView.evaluateJavascript(
                        "javascript:window.NativeBridge._onFCMToken(null)", null
                    )
                }
            }
        }
    }

    @JavascriptInterface
    fun subscribeToTopic(topic: String) {
        Log.d(TAG, "subscribeToTopic: $topic")
        FirebaseMessaging.getInstance().subscribeToTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    Log.d(TAG, "Subscribed to topic: $topic")
                } else {
                    Log.e(TAG, "Failed to subscribe to topic: $topic", task.exception)
                }
            }
    }

    @JavascriptInterface
    fun unsubscribeFromTopic(topic: String) {
        Log.d(TAG, "unsubscribeFromTopic: $topic")
        FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    Log.d(TAG, "Unsubscribed from topic: $topic")
                } else {
                    Log.e(TAG, "Failed to unsubscribe from topic: $topic", task.exception)
                }
            }
    }

    // ==================== Utility ====================

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val json = JSONObject().apply {
            put("platform", "android")
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("androidVersion", Build.VERSION.RELEASE)
            put("appVersion", try {
                activity.packageManager.getPackageInfo(activity.packageName, 0).versionName
            } catch (e: Exception) {
                "unknown"
            })
            put("packageName", activity.packageName)
        }
        return json.toString()
    }

    @JavascriptInterface
    fun log(message: String) {
        Log.d(TAG, "WebApp: $message")
    }
}


